/**
 * Prompt дҪ“зі»з»ҹдёҖеҜјеҮә
 *
 * дҪҝз”Ёж–№ејҸпјҡ
 * import { TASKS, buildContextBlock } from '../prompts'
 */

import TOMATO_RULES_TEXT from './tomatoRules'
import { ROLES } from './roles'
import { TASKS, buildContextBlock, TaskType } from './tasks'
import { LOGIC_OUTPUT, REMOVE_AI_OUTPUT, RHYTHM_OUTPUT, SLAP_FACE_OUTPUT } from './outputs'

export { TOMATO_RULES_TEXT, ROLES, TASKS, buildContextBlock, type TaskType }
export { LOGIC_OUTPUT, REMOVE_AI_OUTPUT, RHYTHM_OUTPUT, SLAP_FACE_OUTPUT }

// еҝ«жҚ·еҮҪж•°пјҡжһ„е»әйҖ»иҫ‘ж ЎйӘҢзҡ„ prompt
export function buildLogicCheckPrompt(
  taskType: 'power' | 'timeline' | 'character' | 'causal',
  chapterContent: string,
  context: {
    facts?: string
    characters?: string
    worldRules?: string
  }
): string {
  const taskKey = taskType + 'Check' as keyof typeof TASKS
  const task = TASKS[taskKey]
  const contextBlock = buildContextBlock({
    chapterContent,
    facts: context.facts,
    characters: context.characters,
    worldRules: context.worldRules,
  })

  return task.role_persona + '\n\n' + contextBlock + '\n' + task.task
}

// еҝ«жҚ·еҮҪж•°пјҡжһ„е»әеҺ»AIе‘і prompt
export function buildRemoveAIPrompt(
  selectedText: string,
  context: {
    facts?: string
    characters?: string
  }
): string {
  const task = TASKS.removeAITrace
  const contextBlock = buildContextBlock({
    chapterContent: '',
    facts: context.facts,
    characters: context.characters,
  })

  const prompt = task.task.replace('{selectedText}', selectedText)
  return task.role_persona + '\n\n' + contextBlock + '\n' + prompt
}

// еҝ«жҚ·еҮҪж•°пјҡжһ„е»әиҠӮеҘҸжЈҖжөӢ prompt
export function buildRhythmCheckPrompt(
  chapterContent: string,
  chapterRange: { start: number; end: number }
): string {
  const task = TASKS.rhythmCheck
  const contextBlock = buildContextBlock({
    chapterContent,
    chapterRange,
  })

  return task.role_persona + '\n\n' + contextBlock + '\n' + task.task
}

export default {
  TOMATO_RULES_TEXT,
  ROLES,
  TASKS,
  buildContextBlock,
  buildLogicCheckPrompt,
  buildRemoveAIPrompt,
  buildRhythmCheckPrompt,
}

/**
 * AI д»»еҠЎе®ҡд№ү
 */

import TOMATO_RULES_TEXT from './tomatoRules'

// дёҠдёӢж–Үжһ„е»әжЁЎжқҝ
export function buildContextBlock(params: {
  chapterContent: string
  facts?: string
  characters?: string
  worldRules?: string
  chapterRange?: { start: number; end: number }
}): string {
  const { chapterContent, facts, characters, worldRules, chapterRange } = params

  let ctx = ''

  if (chapterRange) {
    ctx += 'гҖҗжЈҖжөӢиҢғеӣҙгҖ‘з¬¬' + chapterRange.start + 'з«  ~ з¬¬' + chapterRange.end + 'з« \n\n'
  }

  ctx += 'гҖҗеҫ…жЈҖжөӢз« иҠӮгҖ‘\n' + chapterContent + '\n\n'

  if (facts) {
    ctx += 'гҖҗе·ІзҹҘдәӢе®һеҸ°иҙҰгҖ‘пјҲвҡ пёҸиҜ·иҮӘиЎҢйӘҢиҜҒеҺҹж–ҮпјҢд»ҘдёӢеҸҜиғҪеӯҳеңЁй”ҷиҜҜпјү\nвҡ пёҸ ' + facts + '\n\n'
  }

  if (characters) {
    ctx += 'гҖҗи§’иүІи®ҫе®ҡгҖ‘пјҲвҡ пёҸиҜ·иҮӘиЎҢйӘҢиҜҒеҺҹж–Үпјү\nвҡ пёҸ ' + characters + '\n\n'
  }

  if (worldRules) {
    ctx += 'гҖҗдё–з•Ңи§Ӯи§„еҲҷгҖ‘\n' + worldRules + '\n\n'
  }

  return ctx
}

// з•ӘиҢ„и§„еҲҷж–Үжң¬пјҲжҸҗеҸ–зү№е®ҡз« иҠӮдҫӣд»»еҠЎдҪҝз”Ёпјү
function extractRules(startMarker: string, endMarker: string): string {
  const start = TOMATO_RULES_TEXT.indexOf(startMarker)
  const end = endMarker ? TOMATO_RULES_TEXT.indexOf(endMarker) : TOMATO_RULES_TEXT.length
  if (start === -1) return ''
  return TOMATO_RULES_TEXT.slice(start, end).trim()
}

